=> "intent summarize(text: Text) -> Text {
    goal: summary
}
pure fn split(s: Text) -> List[Text] {
    return split_on(" ", s)
}
pure fn trim(s: Text) -> Text {
    return trim_leading_and_trailing(s, " ")
}
pure fn to_text(num: Number) -> Text {
    return to_string(num)
}
pure fn summarize(text: Text) -> Text {
    words = split(trim(text), " ")
    summary = join(words, " ") + " (summary of " + text + ")"
    return summary
}
entry main(x: Text) { return summarize(x) }"

